import { useState, useCallback } from "react";
import { Upload, FileText, AlertCircle, CheckCircle, X, Download } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from "@/components/ui/dialog";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";

interface CSVImportDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

interface ParsedStudent {
  firstName: string;
  lastName: string;
  grade: string;
  currentClass?: string;
  gender?: string;
  notes?: string;
  [key: string]: string | undefined;
}

export function CSVImportDialog({ open, onOpenChange }: CSVImportDialogProps) {
  const { toast } = useToast();
  const [file, setFile] = useState<File | null>(null);
  const [parsedData, setParsedData] = useState<ParsedStudent[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  const importMutation = useMutation({
    mutationFn: (students: ParsedStudent[]) => 
      apiRequest("POST", "/api/students/bulk-import", { students }),
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/students"] });
      toast({ 
        title: "Import successful", 
        description: `${data.count || parsedData.length} students imported` 
      });
      handleClose();
    },
    onError: () => {
      toast({ title: "Failed to import students", variant: "destructive" });
    },
  });

  const parseCSV = (text: string): { headers: string[]; data: ParsedStudent[] } => {
    const lines = text.trim().split(/\r?\n/);
    if (lines.length < 2) {
      throw new Error("CSV must have a header row and at least one data row");
    }

    const headerLine = lines[0];
    const headers = headerLine.split(",").map((h) => h.trim().replace(/^"|"$/g, ""));

    const requiredHeaders = ["firstName", "lastName", "grade"];
    const altHeaders: Record<string, string[]> = {
      firstName: ["first_name", "first name", "firstname", "first"],
      lastName: ["last_name", "last name", "lastname", "last"],
      grade: ["grade", "grade_level", "gradelevel", "year"],
      currentClass: ["current_class", "current class", "class"],
      gender: ["gender", "sex"],
      Race: ["race"],
      "Aggregate %": ["aggregate %", "aggregate", "aggregate%"],
      "Maths %": ["maths %", "maths", "math %", "math", "maths%"],
      "English %": ["english %", "english", "english%"],
      "Afrikaans/Isizulu %": ["afrikaans/isizulu %", "afrikaans", "isizulu", "afrikaans%"],
      Medication: ["medication", "meds"],
      "Learner Support": ["learner support", "learner_support", "support"],
      notes: ["notes", "note"],
      parentRequests: ["parent requests", "parent_requests", "parentrequests"],
      parentNotes: ["parent notes", "parent_notes", "parentnotes"],
    };

    const headerMap: Record<string, string> = {};
    headers.forEach((h) => {
      const lowerH = h.toLowerCase();
      for (const [standard, alternatives] of Object.entries(altHeaders)) {
        if (lowerH === standard.toLowerCase() || alternatives.includes(lowerH)) {
          headerMap[h] = standard;
        }
      }
      if (!headerMap[h]) {
        headerMap[h] = h;
      }
    });

    const missingRequired = requiredHeaders.filter(
      (req) => !Object.values(headerMap).includes(req)
    );
    if (missingRequired.length > 0) {
      throw new Error(
        `Missing required columns: ${missingRequired.join(", ")}. ` +
        `Found columns: ${headers.join(", ")}`
      );
    }

    const data: ParsedStudent[] = [];
    for (let i = 1; i < lines.length; i++) {
      const line = lines[i].trim();
      if (!line) continue;

      const values: string[] = [];
      let current = "";
      let inQuotes = false;

      for (const char of line) {
        if (char === '"') {
          inQuotes = !inQuotes;
        } else if (char === "," && !inQuotes) {
          values.push(current.trim());
          current = "";
        } else {
          current += char;
        }
      }
      values.push(current.trim());

      const row: Record<string, string> = {};
      headers.forEach((header, idx) => {
        const standardKey = headerMap[header];
        row[standardKey] = values[idx]?.replace(/^"|"$/g, "") || "";
      });

      if (row.firstName && row.lastName && row.grade) {
        data.push(row as ParsedStudent);
      }
    }

    return { headers: Object.values(headerMap), data };
  };

  const handleFile = useCallback((file: File) => {
    setError(null);
    setParsedData([]);
    setHeaders([]);

    if (!file.name.endsWith(".csv")) {
      setError("Please upload a CSV file");
      return;
    }

    setFile(file);

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result as string;
        const { headers, data } = parseCSV(text);
        setHeaders(headers);
        setParsedData(data);
      } catch (err: any) {
        setError(err.message || "Failed to parse CSV file");
      }
    };
    reader.onerror = () => {
      setError("Failed to read file");
    };
    reader.readAsText(file);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) handleFile(file);
  }, [handleFile]);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback(() => {
    setIsDragging(false);
  }, []);

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const handleImport = () => {
    if (parsedData.length === 0) return;
    importMutation.mutate(parsedData);
  };

  const handleClose = () => {
    setFile(null);
    setParsedData([]);
    setHeaders([]);
    setError(null);
    onOpenChange(false);
  };

  const handleDownloadTemplate = () => {
    const headers = ["firstName", "lastName", "grade", "currentClass", "gender", "Race", "Aggregate %", "Maths %", "English %", "Afrikaans/Isizulu %", "Medication", "Learner Support", "Notes", "Parent Requests", "Parent Notes"];
    const exampleRow = ["John", "Smith", "4", "4A", "Male", "White", "75", "80", "72", "68", "", "", "", "", ""];
    const csvContent = [headers.join(","), exampleRow.join(",")].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = "student-template.csv";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>Import Students from CSV</DialogTitle>
          <DialogDescription>
            Upload a CSV file with student data. Required columns: firstName, lastName, grade.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {!file ? (
            <div
              onDrop={handleDrop}
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors ${
                isDragging
                  ? "border-primary bg-primary/5"
                  : "border-muted-foreground/25 hover:border-muted-foreground/50"
              }`}
            >
              <Upload className="h-10 w-10 mx-auto text-muted-foreground mb-4" />
              <p className="text-sm text-muted-foreground mb-2">
                Drag and drop your CSV file here, or
              </p>
              <div className="flex items-center justify-center gap-2 flex-wrap">
                <label>
                  <input
                    type="file"
                    accept=".csv"
                    onChange={handleFileInput}
                    className="hidden"
                    data-testid="input-csv-file"
                  />
                  <Button variant="outline" asChild>
                    <span className="cursor-pointer">Browse Files</span>
                  </Button>
                </label>
                <Button
                  variant="ghost"
                  onClick={handleDownloadTemplate}
                  data-testid="button-download-template"
                >
                  <Download className="h-4 w-4 mr-2" />
                  Download Template
                </Button>
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="flex items-center gap-3 p-3 bg-muted rounded-lg">
                <FileText className="h-8 w-8 text-primary" />
                <div className="flex-1 min-w-0">
                  <p className="font-medium truncate">{file.name}</p>
                  <p className="text-sm text-muted-foreground">
                    {(file.size / 1024).toFixed(1)} KB
                  </p>
                </div>
                <Button
                  size="icon"
                  variant="ghost"
                  onClick={() => {
                    setFile(null);
                    setParsedData([]);
                    setHeaders([]);
                    setError(null);
                  }}
                  data-testid="button-remove-file"
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>

              {error && (
                <Alert variant="destructive">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              {parsedData.length > 0 && (
                <Alert className="border-green-200 bg-green-50 dark:border-green-800 dark:bg-green-950">
                  <CheckCircle className="h-4 w-4 text-green-600 dark:text-green-400" />
                  <AlertDescription className="text-green-700 dark:text-green-300">
                    Found {parsedData.length} valid student records ready to import.
                  </AlertDescription>
                </Alert>
              )}

              {headers.length > 0 && (
                <div className="space-y-2">
                  <p className="text-sm font-medium">Detected columns:</p>
                  <div className="flex flex-wrap gap-1">
                    {headers.map((h) => (
                      <Badge
                        key={h}
                        variant={["firstName", "lastName", "grade"].includes(h) ? "default" : "secondary"}
                      >
                        {h}
                      </Badge>
                    ))}
                  </div>
                </div>
              )}

              {parsedData.length > 0 && (
                <div className="space-y-2">
                  <p className="text-sm font-medium">Preview (first 5 rows):</p>
                  <div className="border rounded-lg overflow-hidden">
                    <div className="overflow-x-auto">
                      <table className="w-full text-sm">
                        <thead className="bg-muted">
                          <tr>
                            <th className="px-3 py-2 text-left font-medium">First Name</th>
                            <th className="px-3 py-2 text-left font-medium">Last Name</th>
                            <th className="px-3 py-2 text-left font-medium">Grade</th>
                            <th className="px-3 py-2 text-left font-medium">Gender</th>
                          </tr>
                        </thead>
                        <tbody>
                          {parsedData.slice(0, 5).map((student, i) => (
                            <tr key={i} className="border-t">
                              <td className="px-3 py-2">{student.firstName}</td>
                              <td className="px-3 py-2">{student.lastName}</td>
                              <td className="px-3 py-2">{student.grade}</td>
                              <td className="px-3 py-2">{student.gender || "—"}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>
                  {parsedData.length > 5 && (
                    <p className="text-xs text-muted-foreground">
                      And {parsedData.length - 5} more students...
                    </p>
                  )}
                </div>
              )}
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={handleClose} data-testid="button-cancel-import">
            Cancel
          </Button>
          <Button
            onClick={handleImport}
            disabled={parsedData.length === 0 || importMutation.isPending}
            data-testid="button-confirm-import"
          >
            {importMutation.isPending ? "Importing..." : `Import ${parsedData.length} Students`}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

client/src/pages/generate.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Sparkles, Plus, Trash2, Users, AlertCircle, CheckCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Progress } from "@/components/ui/progress";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { useToast } from "@/hooks/use-toast";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useLocation } from "wouter";
import type { ClassConfig, InsertClassConfig, Student, Rule, Characteristic } from "@shared/schema";

export default function GeneratePage() {
  const { toast } = useToast();
  const [, setLocation] = useLocation();
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  const [formData, setFormData] = useState<Partial<InsertClassConfig>>({
    name: "",
    grade: "",
    capacity: 30,
  });

  const { data: classConfigs = [], isLoading: configsLoading } = useQuery<ClassConfig[]>({
    queryKey: ["/api/class-configs"],
  });

  const { data: students = [], isLoading: studentsLoading } = useQuery<Student[]>({
    queryKey: ["/api/students"],
  });

  const { data: rules = [] } = useQuery<Rule[]>({
    queryKey: ["/api/rules"],
  });

  const { data: characteristics = [] } = useQuery<Characteristic[]>({
    queryKey: ["/api/characteristics"],
  });

  const createConfigMutation = useMutation({
    mutationFn: (data: InsertClassConfig) => apiRequest("POST", "/api/class-configs", data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/class-configs"] });
      setIsAddDialogOpen(false);
      resetForm();
      toast({ title: "Class added successfully" });
    },
    onError: () => {
      toast({ title: "Failed to add class", variant: "destructive" });
    },
  });

  const deleteConfigMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/class-configs/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/class-configs"] });
      toast({ title: "Class deleted successfully" });
    },
    onError: () => {
      toast({ title: "Failed to delete class", variant: "destructive" });
    },
  });

  const generateMutation = useMutation({
    mutationFn: () => apiRequest("POST", "/api/generate-classes", {}),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/placements"] });
      setIsGenerating(false);
      toast({ title: "Classes generated successfully!" });
      setLocation("/review");
    },
    onError: () => {
      setIsGenerating(false);
      toast({ title: "Failed to generate classes", variant: "destructive" });
    },
  });

  const resetForm = () => {
    setFormData({
      name: "",
      grade: "",
      capacity: 30,
    });
  };

  const handleSubmit = () => {
    if (!formData.name || !formData.grade) {
      toast({ title: "Please fill in all required fields", variant: "destructive" });
      return;
    }
    createConfigMutation.mutate(formData as InsertClassConfig);
  };

  const handleGenerate = () => {
    setIsGenerating(true);
    generateMutation.mutate();
  };

  const grades = Array.from(new Set(students.map((s) => s.grade))).sort();
  const totalCapacity = classConfigs.reduce((sum, c) => sum + (c.capacity || 30), 0);
  const canGenerate = students.length > 0 && classConfigs.length > 0 && totalCapacity >= students.length;

  const isLoading = configsLoading || studentsLoading;

  if (isLoading) {
    return (
      <div className="p-6 space-y-6">
        <Skeleton className="h-10 w-64" />
        <div className="grid gap-4 md:grid-cols-3">
          {[...Array(3)].map((_, i) => (
            <Skeleton key={i} className="h-32 w-full" />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-3xl font-semibold" data-testid="text-page-title">Generate Classes</h1>
          <p className="text-muted-foreground mt-1">
            Configure your target classes and generate balanced placements
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={() => setIsAddDialogOpen(true)} data-testid="button-add-class">
            <Plus className="h-4 w-4 mr-2" />
            Add Class
          </Button>
          <Button
            onClick={handleGenerate}
            disabled={!canGenerate || isGenerating}
            data-testid="button-generate"
          >
            <Sparkles className="h-4 w-4 mr-2" />
            {isGenerating ? "Generating..." : "Generate Classes"}
          </Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardContent className="pt-6">
            <div className="text-2xl font-bold">{students.length}</div>
            <p className="text-sm text-muted-foreground">Total Students</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="text-2xl font-bold">{classConfigs.length}</div>
            <p className="text-sm text-muted-foreground">Target Classes</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="text-2xl font-bold">{rules.length}</div>
            <p className="text-sm text-muted-foreground">Rules Defined</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="text-2xl font-bold">{characteristics.length}</div>
            <p className="text-sm text-muted-foreground">Characteristics</p>
          </CardContent>
        </Card>
      </div>

      {students.length === 0 && (
        <Alert>
          <AlertCircle className="h-4 w-4" />
          <AlertTitle>No students</AlertTitle>
          <AlertDescription>
            You need to add students before generating classes. Go to the Students page to import or add students.
          </AlertDescription>
        </Alert>
      )}

      {classConfigs.length === 0 && students.length > 0 && (
        <Alert>
          <AlertCircle className="h-4 w-4" />
          <AlertTitle>No target classes defined</AlertTitle>
          <AlertDescription>
            Add at least one target class to generate placements.
          </AlertDescription>
        </Alert>
      )}

      {totalCapacity < students.length && classConfigs.length > 0 && (
        <Alert variant="destructive">
          <AlertCircle className="h-4 w-4" />
          <AlertTitle>Insufficient capacity</AlertTitle>
          <AlertDescription>
            Total class capacity ({totalCapacity}) is less than the number of students ({students.length}). 
            Please add more classes or increase capacity.
          </AlertDescription>
        </Alert>
      )}

      {canGenerate && (
        <Alert className="border-green-200 bg-green-50 dark:border-green-800 dark:bg-green-950">
          <CheckCircle className="h-4 w-4 text-green-600 dark:text-green-400" />
          <AlertTitle className="text-green-800 dark:text-green-200">Ready to generate</AlertTitle>
          <AlertDescription className="text-green-700 dark:text-green-300">
            All requirements met. Click "Generate Classes" to create balanced class placements.
          </AlertDescription>
        </Alert>
      )}

      <div className="space-y-4">
        <h2 className="text-xl font-semibold">Target Classes</h2>
        {classConfigs.length === 0 ? (
          <Card>
            <CardContent className="flex flex-col items-center justify-center py-16">
              <div className="rounded-full bg-muted p-4 mb-4">
                <Users className="h-8 w-8 text-muted-foreground" />
              </div>
              <h3 className="text-lg font-medium mb-2">No classes defined</h3>
              <p className="text-muted-foreground text-center max-w-sm mb-4">
                Define the classes you want to create for student placement.
              </p>
              <Button onClick={() => setIsAddDialogOpen(true)} data-testid="button-add-first-class">
                <Plus className="h-4 w-4 mr-2" />
                Add First Class
              </Button>
            </CardContent>
          </Card>
        ) : (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {classConfigs.map((config) => {
              const gradeStudents = students.filter((s) => s.grade === config.grade);
              const fillPercentage = Math.min(
                100,
                (gradeStudents.length / classConfigs.filter((c) => c.grade === config.grade).length / (config.capacity || 30)) * 100
              );
              return (
                <Card key={config.id} data-testid={`card-class-${config.id}`}>
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between gap-2">
                      <CardTitle className="text-base">{config.name}</CardTitle>
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => deleteConfigMutation.mutate(config.id)}
                        data-testid={`button-delete-class-${config.id}`}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                    <CardDescription>
                      Grade {config.grade} • Capacity: {config.capacity}
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-muted-foreground">Estimated fill</span>
                        <span>{Math.round(fillPercentage)}%</span>
                      </div>
                      <Progress value={fillPercentage} className="h-2" />
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}
      </div>

      {isGenerating && (
        <Card>
          <CardContent className="py-8">
            <div className="flex flex-col items-center justify-center space-y-4">
              <div className="relative">
                <Sparkles className="h-12 w-12 text-primary animate-pulse" />
              </div>
              <h3 className="text-lg font-medium">Generating balanced classes...</h3>
              <p className="text-muted-foreground text-center max-w-sm">
                Our algorithm is working to create the most balanced class placements based on your rules and characteristics.
              </p>
              <Progress className="w-64" />
            </div>
          </CardContent>
        </Card>
      )}

      <Dialog open={isAddDialogOpen} onOpenChange={setIsAddDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Add New Class</DialogTitle>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="name">Class Name *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                placeholder="e.g., 3A, Room 101"
                data-testid="input-class-name"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="grade">Grade *</Label>
              <Input
                id="grade"
                value={formData.grade}
                onChange={(e) => setFormData({ ...formData, grade: e.target.value })}
                placeholder="e.g., 3, K, 5"
                data-testid="input-class-grade"
              />
              {grades.length > 0 && (
                <div className="flex flex-wrap gap-1 mt-2">
                  <span className="text-xs text-muted-foreground mr-1">Quick select:</span>
                  {grades.map((g) => (
                    <Badge
                      key={g}
                      variant="outline"
                      className="cursor-pointer text-xs"
                      onClick={() => setFormData({ ...formData, grade: g })}
                    >
                      {g}
                    </Badge>
                  ))}
                </div>
              )}
            </div>
            <div className="space-y-2">
              <Label htmlFor="capacity">Capacity</Label>
              <Input
                id="capacity"
                type="number"
                min={1}
                max={50}
                value={formData.capacity}
                onChange={(e) => setFormData({ ...formData, capacity: Number(e.target.value) })}
                placeholder="30"
                data-testid="input-class-capacity"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsAddDialogOpen(false)} data-testid="button-cancel">
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              disabled={createConfigMutation.isPending}
              data-testid="button-save-class"
            >
              {createConfigMutation.isPending ? "Saving..." : "Add Class"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

