import type { Express } from "express";
import { createServer, type Server } from "http";
import { storage } from "./storage";
import { setupAuth, isAuthenticated } from "./replitAuth";
import {
  insertStudentSchema,
  insertRuleSchema,
  insertCharacteristicSchema,
  insertClassConfigSchema,
  insertPlacementSchema,
  insertSurveySchema,
  insertScenarioSchema,
  insertTeacherSchema,
  type Student,
  type Rule,
  type ClassConfig,
  type Characteristic,
  type ConflictWarning,
  type ClassGenerationResult,
  type GeneratedClass,
} from "@shared/schema";
import { z } from "zod";

export async function registerRoutes(
  httpServer: Server,
  app: Express
): Promise<Server> {
  // Setup authentication
  await setupAuth(app);

  // Auth routes
  app.get('/api/auth/user', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const user = await storage.getUser(userId);
      res.json(user);
    } catch (error) {
      console.error("Error fetching user:", error);
      res.status(500).json({ message: "Failed to fetch user" });
    }
  });

  // Students CRUD (protected)
  app.get("/api/students", isAuthenticated, async (req, res) => {
    const students = await storage.getStudents();
    res.json(students);
  });

  app.get("/api/students/:id", isAuthenticated, async (req, res) => {
    const student = await storage.getStudent(req.params.id);
    if (!student) {
      return res.status(404).json({ error: "Student not found" });
    }
    res.json(student);
  });

  app.post("/api/students", isAuthenticated, async (req, res) => {
    try {
      const data = insertStudentSchema.parse(req.body);
      const student = await storage.createStudent(data);
      res.status(201).json(student);
    } catch (error) {
      res.status(400).json({ error: "Invalid student data" });
    }
  });

  app.patch("/api/students/:id", isAuthenticated, async (req, res) => {
    const student = await storage.updateStudent(req.params.id, req.body);
    if (!student) {
      return res.status(404).json({ error: "Student not found" });
    }
    res.json(student);
  });

  app.delete("/api/students/:id", isAuthenticated, async (req, res) => {
    const deleted = await storage.deleteStudent(req.params.id);
    if (!deleted) {
      return res.status(404).json({ error: "Student not found" });
    }
    res.status(204).send();
  });

  app.post("/api/students/bulk-import", isAuthenticated, async (req, res) => {
    try {
      const { students } = req.body;
      if (!Array.isArray(students)) {
        return res.status(400).json({ error: "students must be an array" });
      }

      const standardFields = ["firstName", "lastName", "grade", "currentClass", "gender", "notes", "parentRequests", "parentNotes"];
      const existingCharacteristics = await storage.getCharacteristics();
      const existingCharNames = new Set(existingCharacteristics.map(c => c.name));

      // First pass: collect all unique characteristic names that need to be created
      const newCharacteristicsToCreate: { name: string; type: string }[] = [];
      for (const student of students) {
        for (const [key, value] of Object.entries(student)) {
          if (!standardFields.includes(key) && value !== undefined && value !== null && value !== "" && !existingCharNames.has(key)) {
            const type = key.includes("%") ? "percentage" : "category";
            newCharacteristicsToCreate.push({ name: key, type });
            existingCharNames.add(key);
          }
        }
      }

      // Create all new characteristics before importing students
      for (const char of newCharacteristicsToCreate) {
        await storage.createCharacteristic({ name: char.name, type: char.type, options: [], priority: 1 });
      }

      // Process students and extract characteristics from extra columns
      const processedStudents = students.map(student => {
        const characteristics: Record<string, string> = {};
        for (const [key, value] of Object.entries(student)) {
          if (!standardFields.includes(key) && value !== undefined && value !== null && value !== "") {
            characteristics[key] = String(value);
          }
        }
        return {
          firstName: student.firstName,
          lastName: student.lastName,
          grade: student.grade,
          currentClass: student.currentClass,
          gender: student.gender,
          notes: student.notes,
          characteristics
        };
      });

      const result = await storage.bulkImportStudents(processedStudents);
      res.status(201).json(result);
    } catch (error) {
      res.status(400).json({ error: "Failed to import students" });
    }
  });

  app.delete("/api/students", isAuthenticated, async (req, res) => {
    await storage.deleteAllStudents();
    res.status(204).send();
  });

  app.post("/api/students/bulk-delete", isAuthenticated, async (req, res) => {
    try {
      const { ids } = req.body;
      if (!Array.isArray(ids)) {
        return res.status(400).json({ error: "ids must be an array" });
      }
      let deletedCount = 0;
      for (const id of ids) {
        const deleted = await storage.deleteStudent(id);
        if (deleted) deletedCount++;
      }
      res.json({ count: deletedCount });
    } catch (error) {
      res.status(400).json({ error: "Failed to delete students" });
    }
  });

  // Rules CRUD (protected)
  app.get("/api/rules", isAuthenticated, async (req, res) => {
    const rules = await storage.getRules();
    res.json(rules);
  });

  app.get("/api/rules/:id", isAuthenticated, async (req, res) => {
    const rule = await storage.getRule(req.params.id);
    if (!rule) {
      return res.status(404).json({ error: "Rule not found" });
    }
    res.json(rule);
  });

  app.post("/api/rules", isAuthenticated, async (req, res) => {
    try {
      const data = insertRuleSchema.parse(req.body);
      const rule = await storage.createRule(data);
      res.status(201).json(rule);
    } catch (error) {
      res.status(400).json({ error: "Invalid rule data" });
    }
  });

  app.patch("/api/rules/:id", isAuthenticated, async (req, res) => {
    const rule = await storage.updateRule(req.params.id, req.body);
    if (!rule) {
      return res.status(404).json({ error: "Rule not found" });
    }
    res.json(rule);
  });

  app.delete("/api/rules/:id", isAuthenticated, async (req, res) => {
    const deleted = await storage.deleteRule(req.params.id);
    if (!deleted) {
      return res.status(404).json({ error: "Rule not found" });
    }
    res.status(204).send();
  });

  // Characteristics CRUD (protected)
  app.get("/api/characteristics", isAuthenticated, async (req, res) => {
    const characteristics = await storage.getCharacteristics();
    res.json(characteristics);
  });

  app.get("/api/characteristics/:id", isAuthenticated, async (req, res) => {
    const characteristic = await storage.getCharacteristic(req.params.id);
    if (!characteristic) {
      return res.status(404).json({ error: "Characteristic not found" });
    }
    res.json(characteristic);
  });

  app.post("/api/characteristics", isAuthenticated, async (req, res) => {
    try {
      const data = insertCharacteristicSchema.parse(req.body);
      const characteristic = await storage.createCharacteristic(data);
      res.status(201).json(characteristic);
    } catch (error) {
      res.status(400).json({ error: "Invalid characteristic data" });
