import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Layers, Plus, Trash2, RotateCcw, ArrowLeftRight, TrendingUp, TrendingDown, Minus } from "lucide-react";
import type { Scenario, Placement } from "@shared/schema";

export default function ScenariosPage() {
  const { toast } = useToast();
  const [saveDialogOpen, setSaveDialogOpen] = useState(false);
  const [scenarioName, setScenarioName] = useState("");
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [restoreId, setRestoreId] = useState<string | null>(null);
  const [compareScenarios, setCompareScenarios] = useState<[string | null, string | null]>([null, null]);

  const { data: scenarios = [], isLoading } = useQuery<Scenario[]>({
    queryKey: ["/api/scenarios"],
  });

  const { data: placements = [] } = useQuery<Placement[]>({
    queryKey: ["/api/placements"],
  });

  const saveMutation = useMutation({
    mutationFn: async (name: string) => {
      return apiRequest("POST", "/api/scenarios", { name });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/scenarios"] });
      toast({ title: "Scenario saved", description: "Current placements saved successfully" });
      setSaveDialogOpen(false);
      setScenarioName("");
    },
    onError: (error: any) => {
      toast({
        title: "Failed to save scenario",
        description: error.message || "Make sure you have generated classes first",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      return apiRequest("DELETE", `/api/scenarios/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/scenarios"] });
      toast({ title: "Scenario deleted" });
      setDeleteId(null);
      if (compareScenarios[0] === deleteId) setCompareScenarios([null, compareScenarios[1]]);
      if (compareScenarios[1] === deleteId) setCompareScenarios([compareScenarios[0], null]);
    },
    onError: () => {
      toast({ title: "Failed to delete scenario", variant: "destructive" });
    },
  });

  const restoreMutation = useMutation({
    mutationFn: async (id: string) => {
      return apiRequest("POST", `/api/scenarios/${id}/restore`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/placements"] });
      toast({ title: "Scenario restored", description: "Placements have been restored from this scenario" });
      setRestoreId(null);
    },
    onError: () => {
      toast({ title: "Failed to restore scenario", variant: "destructive" });
    },
  });

  const handleSave = () => {
    if (!scenarioName.trim()) {
      toast({ title: "Please enter a name", variant: "destructive" });
      return;
    }
    saveMutation.mutate(scenarioName.trim());
  };

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString() + " " + date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  };

  const handleCompareToggle = (scenarioId: string) => {
    if (compareScenarios[0] === scenarioId) {
      setCompareScenarios([null, compareScenarios[1]]);
    } else if (compareScenarios[1] === scenarioId) {
      setCompareScenarios([compareScenarios[0], null]);
    } else if (!compareScenarios[0]) {
      setCompareScenarios([scenarioId, compareScenarios[1]]);
    } else if (!compareScenarios[1]) {
      setCompareScenarios([compareScenarios[0], scenarioId]);
    } else {
      setCompareScenarios([scenarioId, compareScenarios[1]]);
    }
  };

  const scenario1 = scenarios.find(s => s.id === compareScenarios[0]);
  const scenario2 = scenarios.find(s => s.id === compareScenarios[1]);

  const getBalanceDiff = (val1: number, val2: number) => {
    const diff = val2 - val1;
    if (Math.abs(diff) < 0.1) return { icon: Minus, color: "text-muted-foreground", text: "0" };
    if (diff > 0) return { icon: TrendingUp, color: "text-green-600", text: `+${diff.toFixed(1)}` };
    return { icon: TrendingDown, color: "text-red-600", text: diff.toFixed(1) };
  };

  return (
    <div className="p-6 space-y-6 max-w-6xl mx-auto">
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div className="flex items-center gap-3">
          <Layers className="h-8 w-8 text-primary" />
          <div>
            <h1 className="text-2xl font-bold">Scenarios</h1>
            <p className="text-muted-foreground">Save and compare different placement configurations</p>
          </div>
        </div>
        <Button
          onClick={() => setSaveDialogOpen(true)}
          disabled={placements.length === 0}
          data-testid="button-save-scenario"
        >
          <Plus className="h-4 w-4 mr-2" />
          Save Current
        </Button>
      </div>

      {placements.length === 0 && (
        <Card>
          <CardContent className="pt-6">
            <p className="text-center text-muted-foreground">
              Generate classes first to save scenarios. Go to "Generate Classes" to create placements.
            </p>
          </CardContent>
        </Card>
      )}

      {isLoading ? (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {[1, 2, 3].map(i => (
            <Card key={i}>
              <CardHeader>
                <Skeleton className="h-5 w-32" />
                <Skeleton className="h-4 w-24" />
              </CardHeader>
              <CardContent>
                <Skeleton className="h-20 w-full" />
              </CardContent>
            </Card>
          ))}
        </div>
      ) : scenarios.length === 0 ? (
        <Card>
          <CardContent className="pt-6">
            <p className="text-center text-muted-foreground">
              No scenarios saved yet. Save your current placements to create a scenario.
            </p>
          </CardContent>
        </Card>
      ) : (
        <>
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {scenarios.map((scenario) => {
              const isSelected = compareScenarios.includes(scenario.id);
              const selectionIndex = compareScenarios[0] === scenario.id ? 1 : compareScenarios[1] === scenario.id ? 2 : 0;

              return (
                <Card
                  key={scenario.id}
                  className={isSelected ? "ring-2 ring-primary" : ""}
                  data-testid={`card-scenario-${scenario.id}`}
                >
                  <CardHeader className="pb-2">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <CardTitle className="text-lg truncate flex items-center gap-2">
                          {scenario.name}
                          {isSelected && (
                            <Badge variant="default" className="shrink-0">
                              {selectionIndex}
                            </Badge>
                          )}
                        </CardTitle>
                        <CardDescription>{formatDate(scenario.createdAt)}</CardDescription>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-3">
                    <div className="flex items-center justify-between">
                      <span className="text-sm text-muted-foreground">Overall Balance</span>
                      <Badge variant="secondary">
                        {scenario.balanceMetrics?.overallBalance ?? 0}%
                      </Badge>
                    </div>
                    <div className="flex items-center justify-between">
                      <span className="text-sm text-muted-foreground">Students</span>
                      <span className="text-sm font-medium">{scenario.placements?.length ?? 0}</span>
                    </div>
                    <div className="flex items-center justify-between">
                      <span className="text-sm text-muted-foreground">Classes</span>
                      <span className="text-sm font-medium">
                        {scenario.balanceMetrics?.classBalances?.length ?? 0}
                      </span>
                    </div>

                    <div className="flex gap-2 pt-2 flex-wrap">
                      <Button
                        size="sm"
                        variant={isSelected ? "default" : "outline"}
                        onClick={() => handleCompareToggle(scenario.id)}
                        data-testid={`button-compare-${scenario.id}`}
                      >
                        <ArrowLeftRight className="h-3 w-3 mr-1" />
                        Compare
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => setRestoreId(scenario.id)}
                        data-testid={`button-restore-${scenario.id}`}
                      >
                        <RotateCcw className="h-3 w-3 mr-1" />
                        Restore
                      </Button>
                      <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => setDeleteId(scenario.id)}
                        data-testid={`button-delete-${scenario.id}`}
                      >
                        <Trash2 className="h-3 w-3" />
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>

          {(scenario1 || scenario2) && (
            <Card className="mt-6">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <ArrowLeftRight className="h-5 w-5" />
                  Comparison
                </CardTitle>
                <CardDescription>
                  {scenario1 && scenario2
                    ? `Comparing "${scenario1.name}" vs "${scenario2.name}"`
                    : scenario1
                    ? `Select another scenario to compare with "${scenario1.name}"`
                    : `Select another scenario to compare with "${scenario2?.name}"`}
                </CardDescription>
              </CardHeader>
              <CardContent>
                {scenario1 && scenario2 ? (
                  <div className="space-y-4">
                    <div className="grid grid-cols-3 gap-4 text-sm font-medium border-b pb-2">
                      <div>Metric</div>
                      <div className="text-center">{scenario1.name}</div>
                      <div className="text-center">{scenario2.name}</div>
                    </div>

                    <div className="grid grid-cols-3 gap-4 items-center">
                      <div className="text-muted-foreground">Overall Balance</div>
                      <div className="text-center font-medium">
                        {scenario1.balanceMetrics?.overallBalance ?? 0}%
                      </div>
                      <div className="text-center font-medium flex items-center justify-center gap-1">
                        {scenario2.balanceMetrics?.overallBalance ?? 0}%
                        {(() => {
                          const { icon: Icon, color, text } = getBalanceDiff(
                            scenario1.balanceMetrics?.overallBalance ?? 0,
                            scenario2.balanceMetrics?.overallBalance ?? 0
                          );
                          return (
                            <span className={`flex items-center text-xs ${color}`}>
                              <Icon className="h-3 w-3" />
                              {text}
                            </span>
                          );
                        })()}
                      </div>
                    </div>

                    <div className="grid grid-cols-3 gap-4 items-center">
                      <div className="text-muted-foreground">Total Students</div>
                      <div className="text-center">{scenario1.placements?.length ?? 0}</div>
                      <div className="text-center">{scenario2.placements?.length ?? 0}</div>
                    </div>

                    <div className="border-t pt-4 mt-4">
                      <h4 className="font-medium mb-3">Class Balances</h4>
                      <div className="space-y-2">
                        {scenario1.balanceMetrics?.classBalances?.map((cb1) => {
                          const cb2 = scenario2.balanceMetrics?.classBalances?.find(
                            c => c.className === cb1.className
                          );
                          const { icon: Icon, color, text } = getBalanceDiff(
                            cb1.balance,
                            cb2?.balance ?? 0
                          );

                          return (
                            <div key={cb1.classId} className="grid grid-cols-3 gap-4 items-center text-sm">
                              <div className="text-muted-foreground">{cb1.className}</div>
                              <div className="text-center">{cb1.balance}%</div>
                              <div className="text-center flex items-center justify-center gap-1">
                                {cb2?.balance ?? "N/A"}%
                                {cb2 && (
                                  <span className={`flex items-center text-xs ${color}`}>
                                    <Icon className="h-3 w-3" />
                                    {text}
                                  </span>
                                )}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                ) : (
                  <p className="text-muted-foreground text-center py-4">
                    Click "Compare" on two scenarios to see a side-by-side comparison.
                  </p>
                )}
              </CardContent>
            </Card>
          )}
        </>
      )}

      <Dialog open={saveDialogOpen} onOpenChange={setSaveDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Save Scenario</DialogTitle>
            <DialogDescription>
              Save the current class placements as a named scenario for later comparison.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="scenario-name">Scenario Name</Label>
              <Input
                id="scenario-name"
                placeholder="e.g., Initial Draft, Optimized Version"
                value={scenarioName}
                onChange={(e) => setScenarioName(e.target.value)}
                data-testid="input-scenario-name"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setSaveDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleSave}
              disabled={saveMutation.isPending}
              data-testid="button-confirm-save"
            >
              {saveMutation.isPending ? "Saving..." : "Save Scenario"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Scenario</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this scenario? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => deleteId && deleteMutation.mutate(deleteId)}
              data-testid="button-confirm-delete"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <AlertDialog open={!!restoreId} onOpenChange={() => setRestoreId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Restore Scenario</AlertDialogTitle>
            <AlertDialogDescription>
              This will replace your current placements with the ones from this scenario. Are you sure you want to continue?
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => restoreId && restoreMutation.mutate(restoreId)}
              data-testid="button-confirm-restore"
            >
              Restore
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

shared/schema.ts.content:
import { pgTable, text, varchar, integer, boolean, jsonb, timestamp, index } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";
import { sql } from "drizzle-orm";

// Session storage table for Replit Auth
export const sessions = pgTable(
  "sessions",
  {
    sid: varchar("sid").primaryKey(),
    sess: jsonb("sess").notNull(),
    expire: timestamp("expire").notNull(),
  },
  (table) => [index("IDX_session_expire").on(table.expire)],
);

// Student model
export const students = pgTable("students", {
  id: varchar("id", { length: 36 }).primaryKey(),
  studentId: text("student_id"),
  firstName: text("first_name").notNull(),
  lastName: text("last_name").notNull(),
  grade: text("grade").notNull(),
  currentClass: text("current_class"),
  gender: text("gender"),
  characteristics: jsonb("characteristics").$type<Record<string, string>>().default({}),
  notes: text("notes"),
  parentRequests: text("parent_requests"),
  parentNotes: text("parent_notes"),
  isNew: boolean("is_new").default(false),
  isLeaving: boolean("is_leaving").default(false),
});

export const insertStudentSchema = createInsertSchema(students).omit({ id: true });
export type InsertStudent = z.infer<typeof insertStudentSchema>;
export type Student = typeof students.$inferSelect;

// Rule model (pairing/separation)
export const rules = pgTable("rules", {
  id: varchar("id", { length: 36 }).primaryKey(),
  type: text("type").notNull(), // "pair" or "separate"
  studentId1: varchar("student_id_1", { length: 36 }).notNull(),
  studentId2: varchar("student_id_2", { length: 36 }).notNull(),
  reason: text("reason"),
});

export const insertRuleSchema = createInsertSchema(rules).omit({ id: true });
export type InsertRule = z.infer<typeof insertRuleSchema>;
export type Rule = typeof rules.$inferSelect;

// Characteristic definition model
export const characteristics = pgTable("characteristics", {
  id: varchar("id", { length: 36 }).primaryKey(),
  name: text("name").notNull(),
  type: text("type").notNull(), // "category", "scale", or "percentage"
  options: jsonb("options").$type<string[]>().default([]),
  priority: integer("priority").default(1),
});

export const insertCharacteristicSchema = createInsertSchema(characteristics).omit({ id: true });
export type InsertCharacteristic = z.infer<typeof insertCharacteristicSchema>;
export type Characteristic = typeof characteristics.$inferSelect;

// Class configuration
export const classConfigs = pgTable("class_configs", {
  id: varchar("id", { length: 36 }).primaryKey(),
  name: text("name").notNull(),
  grade: text("grade").notNull(),
  capacity: integer("capacity").default(30),
});

export const insertClassConfigSchema = createInsertSchema(classConfigs).omit({ id: true });
export type InsertClassConfig = z.infer<typeof insertClassConfigSchema>;
export type ClassConfig = typeof classConfigs.$inferSelect;

// Generated class placements
export const placements = pgTable("placements", {
  id: varchar("id", { length: 36 }).primaryKey(),
  studentId: varchar("student_id", { length: 36 }).notNull(),
  classId: varchar("class_id", { length: 36 }).notNull(),
  locked: boolean("locked").default(false),
});

export const insertPlacementSchema = createInsertSchema(placements).omit({ id: true });
export type InsertPlacement = z.infer<typeof insertPlacementSchema>;
export type Placement = typeof placements.$inferSelect;

// Teacher model
export const teachers = pgTable("teachers", {
  id: varchar("id", { length: 36 }).primaryKey(),
  firstName: text("first_name").notNull(),
  lastName: text("last_name").notNull(),
  email: text("email").notNull(),
  currentClass: text("current_class"),
  allocatedClass: text("allocated_class"),
  surveyStatus: text("survey_status").default("Not Sent"),
  surveyDate: text("survey_date"),
});

export const insertTeacherSchema = createInsertSchema(teachers).omit({ id: true });
export type InsertTeacher = z.infer<typeof insertTeacherSchema>;
export type Teacher = typeof teachers.$inferSelect;

// Frontend types for class generation result
export interface GeneratedClass {
  classConfig: ClassConfig;
  students: Student[];
  balanceScores: Record<string, number>;
}

export interface ClassGenerationResult {
  classes: GeneratedClass[];
  overallBalance: number;
  conflicts: ConflictWarning[];
}

export interface ConflictWarning {
  type: "separation" | "pairing" | "capacity";
  message: string;
  studentIds: string[];
  ruleId?: string;
}

export interface BalanceMetric {
  characteristicId: string;
  name: string;
  distribution: { className: string; values: Record<string, number> }[];
  score: number;
}

export interface BoostSuggestion {
  id: string;
  type: "swap";
  student1: {
    id: string;
    name: string;
    currentClass: string;
    currentClassId: string;
  };
  student2: {
    id: string;
    name: string;
    currentClass: string;
    currentClassId: string;
  };
  improvement: number;
  reason: string;
}

export interface BoostResponse {
  currentBalance: number;
  suggestions: BoostSuggestion[];
}

// Teacher surveys for student characteristic ratings and pairing recommendations
export const surveys = pgTable("surveys", {
  id: varchar("id", { length: 36 }).primaryKey(),
  teacherName: text("teacher_name").notNull(),
  studentId: varchar("student_id", { length: 36 }).notNull(),
  characteristicRatings: jsonb("characteristic_ratings").$type<Record<string, string>>().default({}),
  pairWith: jsonb("pair_with").$type<string[]>().default([]),
  separateFrom: jsonb("separate_from").$type<string[]>().default([]),
  notes: text("notes"),
  submittedAt: text("submitted_at").notNull(),
});

export const insertSurveySchema = createInsertSchema(surveys).omit({ id: true });
export type InsertSurvey = z.infer<typeof insertSurveySchema>;
export type Survey = typeof surveys.$inferSelect;

// Scenarios for saving and comparing placement snapshots
export const scenarios = pgTable("scenarios", {
  id: varchar("id", { length: 36 }).primaryKey(),
  name: text("name").notNull(),
  createdAt: text("created_at").notNull(),
  placements: jsonb("placements").$type<{ studentId: string; classId: string }[]>().default([]),
  balanceMetrics: jsonb("balance_metrics").$type<{
    overallBalance: number;
    classBalances: { classId: string; className: string; balance: number }[];
  }>().default({ overallBalance: 0, classBalances: [] }),
});

export const insertScenarioSchema = createInsertSchema(scenarios).omit({ id: true });
export type InsertScenario = z.infer<typeof insertScenarioSchema>;
export type Scenario = typeof scenarios.$inferSelect;

// User storage table for Replit Auth
export const users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  email: varchar("email").unique(),
  firstName: varchar("first_name"),
  lastName: varchar("last_name"),
  profileImageUrl: varchar("profile_image_url"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export type UpsertUser = typeof users.$inferInsert;
export type User = typeof users.$inferSelect;

client/src/components/ui/toast.tsx.content:
import * as React from "react"
import * as ToastPrimitives from "@radix-ui/react-toast"
import { cva, type VariantProps } from "class-variance-authority"
import { X } from "lucide-react"

import { cn } from "@/lib/utils"

const ToastProvider = ToastPrimitives.Provider

const ToastViewport = React.forwardRef<
  React.ElementRef<typeof ToastPrimitives.Viewport>,
  React.ComponentPropsWithoutRef<typeof ToastPrimitives.Viewport>
>(({ className, ...props }, ref) => (
  <ToastPrimitives.Viewport
    ref={ref}
    className={cn(
      "fixed top-0 z-[100] flex max-h-screen w-full flex-col-reverse p-4 sm:bottom-0 sm:right-0 sm:top-auto sm:flex-col md:max-w-[420px]",
      className
    )}
    {...props}
  />
))
ToastViewport.displayName = ToastPrimitives.Viewport.displayName

const toastVariants = cva(
  "group pointer-events-auto relative flex w-full items-center justify-between space-x-4 overflow-hidden rounded-md border p-6 pr-8 shadow-lg transition-all data-[swipe=cancel]:translate-x-0 data-[swipe=end]:translate-x-[var(--radix-toast-swipe-end-x)] data-[swipe=move]:translate-x-[var(--radix-toast-swipe-move-x)] data-[swipe=move]:transition-none data-[state=open]:animate-in data-[state=closed]:animate-out data-[swipe=end]:animate-out data-[state=closed]:fade-out-80 data-[state=closed]:slide-out-to-right-full data-[state=open]:slide-in-from-top-full data-[state=open]:sm:slide-in-from-bottom-full",
  {
    variants: {
      variant: {
        default: "border bg-background text-foreground",
        destructive:
          "destructive group border-destructive bg-destructive text-destructive-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

const Toast = React.forwardRef<
  React.ElementRef<typeof ToastPrimitives.Root>,
  React.ComponentPropsWithoutRef<typeof ToastPrimitives.Root> &
    VariantProps<typeof toastVariants>
>(({ className, variant, ...props }, ref) => {
  return (
    <ToastPrimitives.Root
      ref={ref}
      className={cn(toastVariants({ variant }), className)}
      {...props}
    />
  )
})
Toast.displayName = ToastPrimitives.Root.displayName

const ToastAction = React.forwardRef<
  React.ElementRef<typeof ToastPrimitives.Action>,
  React.ComponentPropsWithoutRef<typeof ToastPrimitives.Action>
>(({ className, ...props }, ref) => (
  <ToastPrimitives.Action
    ref={ref}
    className={cn(
      "inline-flex h-8 shrink-0 items-center justify-center rounded-md border bg-transparent px-3 text-sm font-medium ring-offset-background transition-colors hover:bg-secondary focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 group-[.destructive]:border-muted/40 group-[.destructive]:hover:border-destructive/30 group-[.destructive]:hover:bg-destructive group-[.destructive]:hover:text-destructive-foreground group-[.destructive]:focus:ring-destructive",
      className
    )}
    {...props}
  />
))
ToastAction.displayName = ToastPrimitives.Action.displayName

const ToastClose = React.forwardRef<
  React.ElementRef<typeof ToastPrimitives.Close>,
  React.ComponentPropsWithoutRef<typeof ToastPrimitives.Close>
>(({ className, ...props }, ref) => (
  <ToastPrimitives.Close
    ref={ref}
    className={cn(
      "absolute right-2 top-2 rounded-md p-1 text-foreground/50 opacity-0 transition-opacity hover:text-foreground focus:opacity-100 focus:outline-none focus:ring-2 group-hover:opacity-100 group-[.destructive]:text-red-300 group-[.destructive]:hover:text-red-50 group-[.destructive]:focus:ring-red-400 group-[.destructive]:focus:ring-offset-red-600",
      className
    )}
    toast-close=""
    {...props}
  >
    <X className="h-4 w-4" />
  </ToastPrimitives.Close>
))
ToastClose.displayName = ToastPrimitives.Close.displayName

const ToastTitle = React.forwardRef<
  React.ElementRef<typeof ToastPrimitives.Title>,
  React.ComponentPropsWithoutRef<typeof ToastPrimitives.Title>
>(({ className, ...props }, ref) => (
  <ToastPrimitives.Title
    ref={ref}
    className={cn("text-sm font-semibold", className)}
    {...props}
  />
))
ToastTitle.displayName = ToastPrimitives.Title.displayName

const ToastDescription = React.forwardRef<
  React.ElementRef<typeof ToastPrimitives.Description>,
  React.ComponentPropsWithoutRef<typeof ToastPrimitives.Description>
>(({ className, ...props }, ref) => (
  <ToastPrimitives.Description
    ref={ref}
    className={cn("text-sm opacity-90", className)}
    {...props}
  />
))
ToastDescription.displayName = ToastPrimitives.Description.displayName

type ToastProps = React.ComponentPropsWithoutRef<typeof Toast>

type ToastActionElement = React.ReactElement<typeof ToastAction>

export {
  type ToastProps,
  type ToastActionElement,
  ToastProvider,
  ToastViewport,
  Toast,
  ToastTitle,
  ToastDescription,
  ToastClose,
  ToastAction,
}

